/**
 * Upload a video file to begin bird detection analysis
 * @summary Upload video for analysis
 */
export const getUploadVideoUrl = () => {
  return `/api/analysis/upload`;
};

export const uploadVideo = async (
  uploadVideoBody: UploadVideoBody,
  options?: RequestInit,
): Promise<AnalysisJob> => {
  const formData = new FormData();
  formData.append(`video`, uploadVideoBody.video);
  if (uploadVideoBody.sampleInterval !== undefined) {
    formData.append(
      `sampleInterval`,
      uploadVideoBody.sampleInterval.toString(),
    );
  }

  return customFetch<AnalysisJob>(getUploadVideoUrl(), {
    ...options,
    method: "POST",
    body: formData,
  });
};

